function cor = checkFix(td)global scr visual constant params timeout = 1.00; % maximum fixation check timetCorMin = 0.20; % minimum correct fixation time% determine recorded eyeif ~isfield(const,'DOMEYE') && ~const.TEST    evt = Eyelink('newestfloatsample');    const.DOMEYE = find(evt.gx ~= -32768);endcxm = td.fixLoc(1);cym = td.fixLoc(2);rad = visual.fixCkRad;Eyelink('command','draw_box %d %d %d %d 15', cxm-rad, cym-rad, cxm+rad, cym+rad);% drawFixation(visual.fixCkCol,td.fixLoc);cuerct = CenterRectOnPoint([0,0,12,12],scr.xres/2, scr.yres/2);cuetex = Screen('MakeTexture',scr.main,cat(3,ones(12),CreateCircularAperture(12)),[],[],2);fixrct = CenterRectOnPoint([0,0,34,34],scr.xres/2, scr.yres/2);fixtex = Screen('MakeTexture',scr.main,cat(3,ones(34),CreateCircle(34,3)),[],[],2);barpos = nan(2,2,2);barpos(:,:,1) = [scr.xres/2+[-15,+15]/sqrt(2);scr.yres/2+[-15,+15]/sqrt(2)];barpos(:,:,2) = [scr.xres/2+[-15,+15]/sqrt(2);scr.yres/2+[+15,-15]/sqrt(2)];extrabarpos = nan(2,2,2);extrabarpos(:,:,2) = [scr.xres/2+[-20,0]/sqrt(2);scr.yres/2+[0,-20]/sqrt(2)];extrabarpos(:,:,1) = [scr.xres/2+[-20,0]/sqrt(2);scr.yres/2+[0,20]/sqrt(2)];extrabarpos2 = nan(2,2,2);extrabarpos2(:,:,2) = [scr.xres/2+[0,20]/sqrt(2);scr.yres/2+[20,0]/sqrt(2)];extrabarpos2(:,:,1) = [scr.xres/2+[0,20]/sqrt(2);scr.yres/2+[-20,0]/sqrt(2)];gaborrct = [ ...    CenterRectOnPoint([0,0,parameters.gaborsiz,parameters.gaborsiz],scr.xres/2-parameters.gaborexc,scr.yres/2); ...    CenterRectOnPoint([0,0,parameters.gaborsiz,parameters.gaborsiz],scr.xres/2+parameters.gaborexc,scr.yres/2)];placerct = [ ...    CenterRectOnPoint([0,0,parameters.gaborsiz,parameters.gaborsiz],0, 0-parameters.gaborexc); ...    CenterRectOnPoint([0,0,parameters.gaborsiz,parameters.gaborsiz],0, 0+parameters.gaborexc)];placetex = Screen('MakeTexture',scr.main,cat(3,ones(parameters.gaborsiz),CreateCircle(parameters.gaborsiz,3)),[],[],2);Screen('DrawTexture',scr.main,placetex,[],gaborrct(1,:),[],[],[],0);Screen('DrawTexture',scr.main,placetex,[],gaborrct(2,:),[],[],[],0);Screen('DrawTexture',scr.main,cuetex,[],cuerct,[],[],[],0);Screen('DrawTexture',scr.main,fixtex,[],fixrct,[],[],[],0);Screen('DrawLine',scr.main,[0,0,0],barpos(1,1,1),barpos(2,1,1),barpos(1,2,1),barpos(2,2,1),4);Screen('DrawLine',scr.main,[0,0,0],barpos(1,1,2),barpos(2,1,2),barpos(1,2,2),barpos(2,2,2),4);Screen('DrawLine',scr.main,[0,0,0],extrabarpos(1,1,1),extrabarpos(2,1,1),extrabarpos(1,2,1),extrabarpos(2,2,1),2);Screen('DrawLine',scr.main,[0,0,0],extrabarpos(1,1,2),extrabarpos(2,1,2),extrabarpos(1,2,2),extrabarpos(2,2,2),2);Screen('DrawLine',scr.main,[0,0,0],extrabarpos2(1,1,1),extrabarpos2(2,1,1),extrabarpos2(1,2,1),extrabarpos2(2,2,1),2);Screen('DrawLine',scr.main,[0,0,0],extrabarpos2(1,1,2),extrabarpos2(2,1,2),extrabarpos2(1,2,2),extrabarpos2(2,2,2),2);Screen('DrawingFinished',scr.main);Screen(scr.main,'Flip');Eyelink('message', 'EVENT_FixationCheck');tstart=GetSecs;cor=0;corStart=0;tCor=0;t=tstart;while ((t-tstart) < timeout && tCor<=tCorMin)    [x,y] = getCoord;        if sqrt((x-cxm)^2+(y-cym)^2)<rad        cor = 1;    else        cor = 0;    end	if cor == 1 && corStart == 0		tCorStart = GetSecs; 		corStart = 1;	elseif cor == 1 && corStart == 1		tCor = GetSecs-tCorStart;	else		corStart = 0;	end		t=GetSecs;end